INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'listening', 'Begrüßungen', 'Greetings', 'Lerne grundlegende Begrüßungen auf Deutsch', 'Learn basic greetings in German',
'{"type":"listen_and_choose","instructions":"Höre dir die Begrüßung an und wähle das richtige Bild.","exercises":[{"prompt":"Hallo! Wie geht es dir?","options":["Eine winkende Person","Eine schlafende Person","Jemand beim Essen","Jemand beim Laufen"],"correct":0,"hint":"Das ist eine freundliche Begrüßung","hint_translation":"This is a friendly greeting"},{"prompt":"Auf Wiedersehen! Bis später!","options":["Jemand kommt an","Eine winkende Person (beim Abschied)","Jemand sitzt","Jemand kocht"],"correct":1,"hint":"Jemand geht weg","hint_translation":"Someone is going away"},{"prompt":"Guten Morgen!","options":["Nachthimmel","Sonnenaufgang","Regentag","Sonnenuntergang"],"correct":1,"hint":"Denke daran, wenn du aufwachst","hint_translation":"Think of this when you wake up"},{"prompt":"Gute Nacht! Schlaf gut!","options":["Sonniger Day","Person bei der Arbeit","Mond und Sterne","Spielplatz"],"correct":2,"hint":"Zeit zum Schlafen","hint_translation":"Time to sleep"},{"prompt":"Freut mich, Sie kennenzulernen!","options":["Zwei Personen schütteln Hände","Eine Person allein","Eine wütende Person","Jemand läuft"],"correct":0,"hint":"Jemanden neu treffen","hint_translation":"Meeting someone new"},{"prompt":"Hallo! Schön dich zu sehen!","options":["Eine Gruppe von Freunden","Eine Person allein","Jemand mit einem Hund","Eine Person beim Arbeiten"],"correct":0,"hint":"Es ist eine freundliche Begrüßung unter Freunden.","hint_translation":"It''s a friendly greeting among friends."},{"prompt":"Guten Tag! Wie läuft dein Tag?","options":["Eine Person mit einer Tasse Kaffee","Eine Person beim Sport","Jemand schaut fern","Eine Person telefoniert"],"correct":0,"hint":"Dies geschieht oft am Nachmittag.","hint_translation":"This often happens in the afternoon."},{"prompt":"Schönen Abend!","options":["Jemand beim Abendessen","Eine Person im Büro","Ein Sonnenuntergang","Eine Person im Park"],"correct":2,"hint":"Denke an die Zeit, wenn die Sonne untergeht.","hint_translation":"Think of the time when the sun sets."},{"prompt":"Willkommen!","options":["Eine offene Tür","Eine schlafende Katze","Ein leerer Raum","Eine Person mit einem Koffer"],"correct":0,"hint":"Das ist eine Einladung, hereinzukommen.","hint_translation":"This is an invitation to come in."},{"prompt":"Frohe Weihnachten!","options":["Ein Weihnachtsbaum","Ein Osterkorb","Ein Geburtstagskuchen","Ein Feuerwerk"],"correct":0,"hint":"Denke an Feiertage und Geschenke.","hint_translation":"Think of holidays and gifts."},{"prompt":"Guten Abend! Wie war dein Tag?","options":["Eine Person beim Entspannen","Ein Geschirrspüler","Jemand kocht","Eine Person liest ein Buch"],"correct":0,"hint":"Es ist eine häufige Frage am Abend.","hint_translation":"It''s a common question in the evening."},{"prompt":"Hallo zusammen!","options":["Eine große Gruppe von Menschen","Eine Person alleine","Ein Hund im Park","Eine Katze auf einem Tisch"],"correct":0,"hint":"Das ist eine Begrüßung an mehrere Personen.","hint_translation":"This is a greeting to several people."},{"prompt":"Guten Appetit!","options":["Ein gedeckter Tisch","Eine leere Schüssel","Jemand macht Sport","Ein schmutziger Teller"],"correct":0,"hint":"Es wird oft gesagt, bevor man isst.","hint_translation":"It is often said before one eats."},{"prompt":"Herzlich Willkommen!","options":["Ein festlicher Empfang","Eine geschlossene Tür","Ein leerer Raum","Eine Person mit einem Buch"],"correct":0,"hint":"Es zeigt Freude über den Besuch.","hint_translation":"It shows joy about the visit."},{"prompt":"Guten Morgen! Bist du bereit für den Tag?","options":["Eine Person schläft","Ein Wecker klingelt","Eine Person beim Joggen","Eine Tasse Tee"],"correct":1,"hint":"Es ist der Beginn eines neuen Tages.","hint_translation":"It is the beginning of a new day."},{"prompt":"Viel Spaß!","options":["Ein fröhliches Kind","Ein trauriger Hund","Eine Person beim Arbeiten","Ein leerer Raum"],"correct":0,"hint":"Es wird gesagt, um jemandem Freude zu wünschen.","hint_translation":"It is said to wish someone joy."},{"prompt":"Schön dich zu sehen!","options":["Eine Umarmung","Ein leerer Raum","Ein schlafender Hund","Ein Spielplatz"],"correct":0,"hint":"Es drückt Freude über eine Begegnung aus.","hint_translation":"It expresses joy about a meeting."},{"prompt":"Guten Nachmittag!","options":["Ein Nachmittagstee","Eine schlafende Katze","Eine Person beim Arbeiten","Ein leerer Platz"],"correct":0,"hint":"Es ist eine Begrüßung zur Mittagszeit.","hint_translation":"It is a greeting around midday."},{"prompt":"Frohes neues Jahr!","options":["Ein Feuerwerk","Ein Weihnachtsbaum","Ein Geburtstagskuchen","Ein leerer Raum"],"correct":0,"hint":"Es wird am Ende eines Jahres gesagt.","hint_translation":"It is said at the end of a year."}]}', 1),

('de', 'A1', 'listening', 'Zahlen 1 bis 10', 'Numbers 1 to 10', 'Höre und lerne die Zahlen von eins bis zehn', 'Listen and learn the numbers from one to ten',
'{"type":"listen_and_choose","instructions":"Höre die Zahl und wähle die richtige Ziffer.","exercises":[{"prompt":"Drei","options":["1","3","5","7"],"correct":1,"hint":"Kommt nach zwei","hint_translation":"Comes after two"},{"prompt":"Sieben","options":["4","6","7","9"],"correct":2,"hint":"Kommt nach sechs","hint_translation":"Comes after six"},{"prompt":"Eins","options":["1","2","10","8"],"correct":0,"hint":"Die allererste Zahl","hint_translation":"The very first number"},{"prompt":"Zehn","options":["2","5","8","10"],"correct":3,"hint":"Zwei Hände voll Finger","hint_translation":"Two hands full of fingers"},{"prompt":"Fünf","options":["3","5","4","6"],"correct":1,"hint":"Genau in der Mitte","hint_translation":"Right in the middle"},{"prompt":"Zwei","options":["2","4","6","8"],"correct":0,"hint":"Kommt nach eins","hint_translation":"Comes after one"},{"prompt":"Fünf","options":["2","5","10","12"],"correct":1,"hint":"Kommt nach vier","hint_translation":"Comes after four"},{"prompt":"Acht","options":["3","8","9","11"],"correct":1,"hint":"Kommt nach sieben","hint_translation":"Comes after seven"},{"prompt":"Vier","options":["3","4","5","6"],"correct":1,"hint":"Kommt nach drei","hint_translation":"Comes after three"},{"prompt":"Neun","options":["8","9","10","12"],"correct":1,"hint":"Kommt nach acht","hint_translation":"Comes after eight"},{"prompt":"Sechs","options":["5","6","7","8"],"correct":1,"hint":"Kommt nach fünf","hint_translation":"Comes after five"},{"prompt":"Zehn","options":["9","10","11","12"],"correct":1,"hint":"Kommt nach neun","hint_translation":"Comes after nine"},{"prompt":"Elf","options":["10","11","12","13"],"correct":1,"hint":"Kommt nach zehn","hint_translation":"Comes after ten"},{"prompt":"Zwölf","options":["11","12","13","14"],"correct":1,"hint":"Kommt nach elf","hint_translation":"Comes after eleven"},{"prompt":"Drei","options":["0","3","6","9"],"correct":1,"hint":"Kommt nach zwei","hint_translation":"Comes after two"},{"prompt":"Zero","options":["0","1","2","3"],"correct":0,"hint":"Die allererste Zahl in der Nullreihe","hint_translation":"The very first number in the zero series"},{"prompt":"Dreizehn","options":["12","13","14","15"],"correct":1,"hint":"Kommt nach zwölf","hint_translation":"Comes after twelve"},{"prompt":"Vierzehn","options":["13","14","15","16"],"correct":1,"hint":"Kommt nach dreizehn","hint_translation":"Comes after thirteen"},{"prompt":"Fünfzehn","options":["14","15","16","17"],"correct":1,"hint":"Kommt nach vierzehn","hint_translation":"Comes after fourteen"}]}', 2),

('de', 'A1', 'listening', 'Farben um uns herum', 'Colors Around Us', 'Höre und identifiziere Farben', 'Listen and identify colors',
'{"type":"listen_and_choose","instructions":"Höre den Farbnamen und wähle die richtige Farbe.","exercises":[{"prompt":"Rot","options":["🔴","🔵","🟢","🟡"],"correct":0,"hint":"Die Farbe der Feuerwehr","hint_translation":"The color of the fire truck"},{"prompt":"Blau","options":["🟠","🔵","🟣","🔴"],"correct":1,"hint":"Die Farbe des Himmels","hint_translation":"The color of the sky"},{"prompt":"Grün","options":["🟡","🔴","🟢","🔵"],"correct":2,"hint":"Die Farbe von Gras","hint_translation":"The color of grass"},{"prompt":"Gelb","options":["🟢","🟣","🔴","🟡"],"correct":3,"hint":"Die Farbe der Sonne","hint_translation":"The color of the sun"},{"prompt":"Orange","options":["🟠","🔵","🟢","🟡"],"correct":0,"hint":"Eine Frucht hat diesen Namen auch","hint_translation":"A fruit has this name too"},{"prompt":"Gelb","options":["🟡","🟢","🔵","🔴"],"correct":0,"hint":"Die Farbe der Sonne","hint_translation":"The color of the sun"},{"prompt":"Lila","options":["🟠","🟣","🔴","🟡"],"correct":1,"hint":"Die Farbe von Lavendel","hint_translation":"The color of lavender"},{"prompt":"Orange","options":["🟠","🔴","🔵","🟡"],"correct":0,"hint":"Die Farbe der Orange","hint_translation":"The color of the orange"},{"prompt":"Schwarz","options":["⚫","🔴","🟢","🟡"],"correct":0,"hint":"Die Farbe der Nacht","hint_translation":"The color of the night"},{"prompt":"Weiß","options":["⚪","🟣","🔵","🟡"],"correct":0,"hint":"Die Farbe des Schnees","hint_translation":"The color of the snow"},{"prompt":"Braun","options":["🟤","🟡","🔵","🔴"],"correct":0,"hint":"Die Farbe von Schokolade","hint_translation":"The color of chocolate"},{"prompt":"Türkis","options":["🟢","🔵","🟣","🟡"],"correct":1,"hint":"Die Farbe des Meeres","hint_translation":"The color of the sea"},{"prompt":"Rosa","options":["🟠","🔴","🟡","🟣"],"correct":3,"hint":"Die Farbe der Blume","hint_translation":"The color of the flower"},{"prompt":"Gold","options":["🟡","⚪","🟤","🟣"],"correct":0,"hint":"Die Farbe von Schmuck","hint_translation":"The color of jewelry"},{"prompt":"Silber","options":["⚪","🟤","🔵","🟢"],"correct":0,"hint":"Die Farbe von Münzen","hint_translation":"The color of coins"},{"prompt":"Beige","options":["🟤","⚪","🟡","🟢"],"correct":0,"hint":"Eine helle Braunschattierung","hint_translation":"A light brown shade"},{"prompt":"Cyan","options":["🔵","🟢","🟣","🟡"],"correct":0,"hint":"Die Farbe von Wasser","hint_translation":"The color of water"},{"prompt":"Violett","options":["🟣","🔴","🟡","🔵"],"correct":0,"hint":"Die Farbe von Trauben","hint_translation":"The color of grapes"},{"prompt":"Hellblau","options":["🔵","🟠","⚪","🟡"],"correct":0,"hint":"Die Farbe des Himmels an einem klaren Tag","hint_translation":"The color of the sky on a clear day"},{"prompt":"Khaki","options":["🟤","🟡","🟢","⚪"],"correct":0,"hint":"Die Farbe von Militäruniformen","hint_translation":"The color of military uniforms"}]}', 3),

('de', 'A1', 'listening', 'Meine Familie', 'My Family', 'Höre und lerne die Namen der Familienmitglieder', 'Listen and learn the names of family members',
'{"type":"listen_and_choose","instructions":"Höre zu und wähle die beschriebene Person.","exercises":[{"prompt":"Das ist meine Mutter. Sie ist sehr nett.","options":["👩 Mutter","👨 Vater","👦 Bruder","👧 Schwester"],"correct":0,"hint":"Ein weiblicher Elternteil","hint_translation":"A female parent"},{"prompt":"Mein Vater kocht gerne.","options":["👧 Schwester","👦 Bruder","👨 Vater","👩 Mutter"],"correct":2,"hint":"Ein männlicher Elternteil","hint_translation":"A male parent"},{"prompt":"Ich habe eine kleine Schwester.","options":["👦 Bruder","👨 Vater","👩 Mutter","👧 Schwester"],"correct":3,"hint":"Ein junges weibliches Geschwisterkind","hint_translation":"A young female sibling"},{"prompt":"Mein Bruder spielt Fußball.","options":["👦 Bruder","👧 Schwester","👩 Mutter","👨 Vater"],"correct":0,"hint":"Ein männliches Geschwisterkind","hint_translation":"A male sibling"},{"prompt":"Oma erzählt uns Geschichten.","options":["👨 Vater","👩 Mutter","👵 Oma","👦 Bruder"],"correct":2,"hint":"Die Mutter deiner Eltern","hint_translation":"The mother of your parents"},{"prompt":"Mein Bruder spielt Fußball.","options":["👦 Bruder","👧 Schwester","👨 Vater","👩 Mutter"],"correct":0,"hint":"Ein männliches Geschwisterkind","hint_translation":"A male sibling"},{"prompt":"Meine Schwester liest gerne Bücher.","options":["👧 Schwester","👦 Bruder","👩 Mutter","👨 Vater"],"correct":0,"hint":"Ein weibliches Geschwisterkind","hint_translation":"A female sibling"},{"prompt":"Mein Vater fährt oft mit dem Fahrrad.","options":["👩 Mutter","👧 Schwester","👦 Bruder","👨 Vater"],"correct":3,"hint":"Ein männlicher Elternteil","hint_translation":"A male parent"},{"prompt":"Meine Mutter hat lange Haare.","options":["👩 Mutter","👦 Bruder","👨 Vater","👧 Schwester"],"correct":0,"hint":"Ein weiblicher Elternteil","hint_translation":"A female parent"},{"prompt":"Ich habe einen Hund. Er gehört meinem Bruder.","options":["👦 Bruder","👧 Schwester","👨 Vater","👩 Mutter"],"correct":0,"hint":"Ein männliches Geschwisterkind","hint_translation":"A male sibling"},{"prompt":"Meine Schwester spielt Klavier.","options":["👧 Schwester","👦 Bruder","👨 Vater","👩 Mutter"],"correct":0,"hint":"Ein weibliches Geschwisterkind","hint_translation":"A female sibling"},{"prompt":"Mein Vater arbeitet im Büro.","options":["👩 Mutter","👧 Schwester","👦 Bruder","👨 Vater"],"correct":3,"hint":"Ein männlicher Elternteil","hint_translation":"A male parent"},{"prompt":"Meine Mutter backt oft Kuchen.","options":["👧 Schwester","👦 Bruder","👨 Vater","👩 Mutter"],"correct":3,"hint":"Ein weiblicher Elternteil","hint_translation":"A female parent"},{"prompt":"Mein Bruder hat viele Freunde.","options":["👦 Bruder","👧 Schwester","👩 Mutter","👨 Vater"],"correct":0,"hint":"Ein männliches Geschwisterkind","hint_translation":"A male sibling"},{"prompt":"Ich bin die älteste Schwester in meiner Familie.","options":["👦 Bruder","👧 Schwester","👩 Mutter","👨 Vater"],"correct":1,"hint":"Ein weibliches Geschwisterkind","hint_translation":"A female sibling"},{"prompt":"Mein Vater hat einen großen Garten.","options":["👩 Mutter","👧 Schwester","👦 Bruder","👨 Vater"],"correct":3,"hint":"Ein männlicher Elternteil","hint_translation":"A male parent"},{"prompt":"Meine Schwester malt gerne Bilder.","options":["👧 Schwester","👦 Bruder","👨 Vater","👩 Mutter"],"correct":0,"hint":"Ein weibliches Geschwisterkind","hint_translation":"A female sibling"},{"prompt":"Mein Bruder ist sehr sportlich.","options":["👦 Bruder","👧 Schwester","👩 Mutter","👨 Vater"],"correct":0,"hint":"Ein männliches Geschwisterkind","hint_translation":"A male sibling"},{"prompt":"Meine Mutter liebt es zu reisen.","options":["👩 Mutter","👧 Schwester","👦 Bruder","👨 Vater"],"correct":0,"hint":"Ein weiblicher Elternteil","hint_translation":"A female parent"},{"prompt":"Mein Vater spielt gerne Schach.","options":["👩 Mutter","👧 Schwester","👦 Bruder","👨 Vater"],"correct":3,"hint":"Ein männlicher Elternteil","hint_translation":"A male parent"}]}', 4),

('de', 'A1', 'listening', 'Tiere, die ich kenne', 'Animals I Know', 'Höre Tiernamen und Geräusche', 'Listen to animal names and sounds',
'{"type":"listen_and_choose","instructions":"Höre zu und wähle das richtige Tier.","exercises":[{"prompt":"Die Katze sagt miau.","options":["🐱","🐶","🐦","🐸"],"correct":0,"hint":"Ein kleines Haustier mit weichem Fell","hint_translation":"A small pet with soft fur"},{"prompt":"Der Hund bellt.","options":["🐱","🐶","🐟","🐘"],"correct":1,"hint":"Ein treues Haustier, das Stöckchen holt","hint_translation":"A faithful pet that fetches sticks"},{"prompt":"Schau mal, der große Elefant!","options":["🐁","🐦","🐘","🐟"],"correct":2,"hint":"Das größte Landsäugetier","hint_translation":"The largest land mammal"},{"prompt":"Der Vogel singt.","options":["🐸","🐦","🐱","🐶"],"correct":1,"hint":"Er hat Flügel und Federn","hint_translation":"It has wings and feathers"},{"prompt":"Der Fisch schwimmt im Wasser.","options":["🐦","🐱","🐶","🐟"],"correct":3,"hint":"Er lebt unter Wasser","hint_translation":"It lives under water"},{"prompt":"Der Papagei sagt hallo.","options":["🐦","🐕","🐈","🐍"],"correct":0,"hint":"Ein bunter Vogel, der sprechen kann","hint_translation":"A colorful bird that can talk"},{"prompt":"Die Kuh macht muuh.","options":["🐄","🐖","🐑","🐐"],"correct":0,"hint":"Ein Tier, das Milch gibt","hint_translation":"An animal that gives milk"},{"prompt":"Die Maus piepst.","options":["🐁","🐇","🐒","🐢"],"correct":0,"hint":"Ein kleines Nagetier, das Käse liebt","hint_translation":"A small rodent that loves cheese"},{"prompt":"Die Ente quakt.","options":["🐦","🐕","🐠","🦆"],"correct":3,"hint":"Ein Vogel, der oft in Teichen zu finden ist","hint_translation":"A bird often found in ponds"},{"prompt":"Der Löwe brüllt.","options":["🦁","🐯","🐻","🐺"],"correct":0,"hint":"Der König der Tiere","hint_translation":"The king of the animals"},{"prompt":"Die Schildkröte ist langsam.","options":["🐍","🐢","🐇","🐦"],"correct":1,"hint":"Ein Reptil mit einem harten Panzer","hint_translation":"A reptile with a hard shell"},{"prompt":"Der Frosch quakt.","options":["🐸","🦙","🐦","🐍"],"correct":0,"hint":"Ein Tier, das oft in der Nähe von Wasser lebt","hint_translation":"An animal that often lives near water"},{"prompt":"Der Affe schwingt sich von Baum zu Baum.","options":["🐒","🐻","🐨","🦁"],"correct":0,"hint":"Ein verspieltes Tier, das Bananen mag","hint_translation":"A playful animal that loves bananas"},{"prompt":"Die Gans schnattert.","options":["🦢","🦆","🐦","🦢"],"correct":1,"hint":"Ein Vogel, der oft in Gruppen lebt","hint_translation":"A bird that often lives in groups"},{"prompt":"Der Tiger hat Streifen.","options":["🐅","🐻","🐯","🐆"],"correct":0,"hint":"Ein großes Raubtier mit orangefarbenem Fell","hint_translation":"A large predator with orange fur"},{"prompt":"Der Fisch schwimmt im Wasser.","options":["🐠","🐸","🐢","🐉"],"correct":0,"hint":"Ein Tier, das Kiemen hat","hint_translation":"An animal that has gills"},{"prompt":"Der Hase hüpft.","options":["🐇","🐁","🐕","🦘"],"correct":0,"hint":"Ein schnelles Tier mit langen Ohren","hint_translation":"A fast animal with long ears"},{"prompt":"Der Bär brummt.","options":["🐻","🐯","🐺","🦁"],"correct":0,"hint":"Ein großes Tier, das Honig liebt","hint_translation":"A large animal that loves honey"},{"prompt":"Der Pinguin watschelt.","options":["🐧","🦅","🦆","🐦"],"correct":0,"hint":"Ein Vogel, der nicht fliegen kann","hint_translation":"A bird that cannot fly"}]}', 5);

