INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'speaking', 'Sag Hallo', 'Say Hello', 'Übe, Leute zu begrüßen', 'Practice greeting people',
'{"type":"speak_and_compare","instructions":"Höre dir den Satz an und sprich ihn laut aus.","exercises":[{"prompt":"Hallo!","expected":"hallo","hint":"Eine einfache Begrüßung","hint_translation":"A simple greeting"},{"prompt":"Guten Morgen!","expected":"guten morgen","hint":"Was man am Morgen sagt","hint_translation":"What you say in the morning"},{"prompt":"Wie geht es dir?","expected":"wie geht es dir","hint":"Fragen, wie sich jemand fühlt","hint_translation":"Asking how someone feels"},{"prompt":"Freut mich!","expected":"freut mich","hint":"Wenn man jemanden neu trifft","hint_translation":"When meeting someone new"},{"prompt":"Tschüss!","expected":"tschüss","hint":"Wenn man geht","hint_translation":"When you leave"},{"prompt":"Guten Abend!","expected":"guten abend","hint":"Was man am Abend sagt","hint_translation":"What you say in the evening"},{"prompt":"Danke schön!","expected":"danke schön","hint":"Ein Ausdruck der Dankbarkeit","hint_translation":"An expression of gratitude"},{"prompt":"Tschüss!","expected":"tschüss","hint":"Eine informelle Verabschiedung","hint_translation":"An informal goodbye"},{"prompt":"Bis bald!","expected":"bis bald","hint":"Eine Verabschiedung mit Hoffnung auf ein baldiges Wiedersehen","hint_translation":"A goodbye with hope to see someone soon"},{"prompt":"Wie heißt du?","expected":"wie heißt du","hint":"Fragen nach dem Namen","hint_translation":"Asking for someone''s name"},{"prompt":"Ich liebe dich!","expected":"ich liebe dich","hint":"Ein Ausdruck von Zuneigung","hint_translation":"An expression of affection"},{"prompt":"Was machst du heute?","expected":"was machst du heute","hint":"Fragen nach den Plänen für den Tag","hint_translation":"Asking about plans for the day"},{"prompt":"Woher kommst du?","expected":"woher kommst du","hint":"Fragen nach dem Herkunftsort","hint_translation":"Asking about someone''s place of origin"},{"prompt":"Ich verstehe nicht.","expected":"ich verstehe nicht","hint":"Ein Hinweis darauf, dass man etwas nicht versteht","hint_translation":"A hint that one does not understand something"},{"prompt":"Können Sie das bitte wiederholen?","expected":"können sie das bitte wiederholen","hint":"Fragen, um etwas noch einmal zu hören","hint_translation":"Asking to hear something again"},{"prompt":"Entschuldigung!","expected":"entschuldigung","hint":"Ein Ausdruck, um Aufmerksamkeit zu erlangen oder sich zu entschuldigen","hint_translation":"An expression to get attention or apologize"},{"prompt":"Ich bin müde.","expected":"ich bin müde","hint":"Ein Hinweis auf Erschöpfung","hint_translation":"A hint of tiredness"},{"prompt":"Das ist interessant.","expected":"das ist interessant","hint":"Ein Ausdruck des Interesses","hint_translation":"An expression of interest"},{"prompt":"Kannst du mir helfen?","expected":"kannst du mir helfen","hint":"Fragen um Hilfe zu bitten","hint_translation":"Asking for help"},{"prompt":"Ich mag das.","expected":"ich mag das","hint":"Ein Ausdruck des Gefallens","hint_translation":"An expression of liking"}]}', 1),

('de', 'A1', 'speaking', 'Über mich', 'About Me', 'Übe, dich vorzustellen', 'Practice introducing yourself',
'{"type":"speak_and_compare","instructions":"Sprich jeden Satz laut aus.","exercises":[{"prompt":"Ich heiße...","expected":"ich heiße","hint":"Nenne deinen Namen","hint_translation":"Say your name"},{"prompt":"Ich bin sechs Jahre alt.","expected":"ich bin sechs jahre alt","hint":"Nenne dein Alter","hint_translation":"Say your age"},{"prompt":"Ich spiele gerne.","expected":"ich spiele gerne","hint":"Etwas, das dir Spaß macht","hint_translation":"Something that is fun for you"},{"prompt":"Ich bin glücklich!","expected":"ich bin glücklich","hint":"Wie du dich fühlst","hint_translation":"How you feel"},{"prompt":"Danke schön!","expected":"danke schön","hint":"Sei höflich","hint_translation":"Be polite"},{"prompt":"Ich komme aus Deutschland.","expected":"ich komme aus deutschland","hint":"Nenne dein Herkunftsland","hint_translation":"Say your country of origin"},{"prompt":"Ich mag Tiere.","expected":"ich mag tiere","hint":"Etwas, das dir gefällt","hint_translation":"Something you like"},{"prompt":"Ich habe einen Hund.","expected":"ich habe einen hund","hint":"Hast du ein Haustier?","hint_translation":"Do you have a pet?"},{"prompt":"Ich liebe Schokolade.","expected":"ich liebe schokolade","hint":"Etwas, das du gerne isst","hint_translation":"Something you like to eat"},{"prompt":"Ich gehe zur Schule.","expected":"ich gehe zur schule","hint":"Was machst du jeden Tag?","hint_translation":"What do you do every day?"},{"prompt":"Ich spiele Fußball.","expected":"ich spiele fußball","hint":"Ein Sport, den du spielst","hint_translation":"A sport you play"},{"prompt":"Ich lese Bücher.","expected":"ich lese bücher","hint":"Eine Aktivität, die du gerne machst","hint_translation":"An activity you enjoy"},{"prompt":"Ich höre Musik.","expected":"ich höre musik","hint":"Etwas, das du gerne tust","hint_translation":"Something you like to do"},{"prompt":"Ich habe viele Freunde.","expected":"ich habe viele freunde","hint":"Sprich über deine Freunde","hint_translation":"Talk about your friends"},{"prompt":"Ich esse gerne Pizza.","expected":"ich esse gerne pizza","hint":"Nenne dein Lieblingsessen","hint_translation":"Say your favorite food"},{"prompt":"Ich sehe gerne Filme.","expected":"ich sehe gerne filme","hint":"Was machst du in deiner Freizeit?","hint_translation":"What do you do in your free time?"},{"prompt":"Ich fahre mit dem Fahrrad.","expected":"ich fahre mit dem fahrrad","hint":"Wie bewegst du dich fort?","hint_translation":"How do you get around?"},{"prompt":"Ich mag den Sommer.","expected":"ich mag den sommer","hint":"Welche Jahreszeit magst du?","hint_translation":"Which season do you like?"},{"prompt":"Ich spiele Klavier.","expected":"ich spiele klavier","hint":"Ein Instrument, das du spielst","hint_translation":"An instrument you play"},{"prompt":"Ich mache gerne Sport.","expected":"ich mache gerne sport","hint":"Etwas, das du aktiv machst","hint_translation":"Something you do actively"}]}', 2),

('de', 'A1', 'speaking', 'Zähl mit mir', 'Count With Me', 'Übe, Zahlen laut auszusprechen', 'Practice saying numbers out loud',
'{"type":"speak_and_compare","instructions":"Sprich jede Zahl deutlich aus.","exercises":[{"prompt":"Eins","expected":"eins","hint":"Die erste Zahl","hint_translation":"The first number"},{"prompt":"Zwei","expected":"zwei","hint":"Nach eins","hint_translation":"After one"},{"prompt":"Fünf","expected":"fünf","hint":"Die Hälfte von zehn","hint_translation":"Half of ten"},{"prompt":"Acht","expected":"acht","hint":"Nach sieben","hint_translation":"After seven"},{"prompt":"Zehn","expected":"zehn","hint":"Alle Finger","hint_translation":"All fingers"},{"prompt":"Drei","expected":"drei","hint":"Zwei plus eins","hint_translation":"Two plus one"},{"prompt":"Vier","expected":"vier","hint":"Zwei mal zwei","hint_translation":"Two times two"},{"prompt":"Sechs","expected":"sechs","hint":"Zwei mal drei","hint_translation":"Two times three"},{"prompt":"Sieben","expected":"sieben","hint":"Nach sechs","hint_translation":"After six"},{"prompt":"Acht","expected":"acht","hint":"Zwei mal vier","hint_translation":"Two times four"},{"prompt":"Neun","expected":"neun","hint":"Drei mal drei","hint_translation":"Three times three"},{"prompt":"Zehn","expected":"zehn","hint":"Die erste zweistellige Zahl","hint_translation":"The first two-digit number"},{"prompt":"Elf","expected":"elf","hint":"Zehn plus eins","hint_translation":"Ten plus one"},{"prompt":"Zwölf","expected":"zwölf","hint":"Zehn plus zwei","hint_translation":"Ten plus two"},{"prompt":"Dreizehn","expected":"dreizehn","hint":"Zehn plus drei","hint_translation":"Ten plus three"},{"prompt":"Vierzehn","expected":"vierzehn","hint":"Zehn plus vier","hint_translation":"Ten plus four"},{"prompt":"Fünfzehn","expected":"fünfzehn","hint":"Zehn plus fünf","hint_translation":"Ten plus five"},{"prompt":"Sechzehn","expected":"sechzehn","hint":"Zehn plus sechs","hint_translation":"Ten plus six"},{"prompt":"Siebzehn","expected":"siebzehn","hint":"Zehn plus sieben","hint_translation":"Ten plus seven"},{"prompt":"Achtzehn","expected":"achtzehn","hint":"Zehn plus acht","hint_translation":"Ten plus eight"},{"prompt":"Neunzehn","expected":"neunzehn","hint":"Zehn plus neun","hint_translation":"Ten plus nine"}]}', 3),

('de', 'A1', 'speaking', 'Nenne die Farben', 'Name the Colors', 'Farbnamen laut sagen', 'Say color names out loud',
'{"type":"speak_and_compare","instructions":"Schau dir die Farbe an und sag ihren Namen.","exercises":[{"prompt":"Rot 🔴","expected":"rot","hint":"Farbe des Feuers","hint_translation":"Color of fire"},{"prompt":"Blau 🔵","expected":"blau","hint":"Farbe des Meeres","hint_translation":"Color of the sea"},{"prompt":"Grün 🟢","expected":"grün","hint":"Farbe der Blätter","hint_translation":"Color of leaves"},{"prompt":"Gelb 🟡","expected":"gelb","hint":"Farbe der Bananen","hint_translation":"Color of bananas"},{"prompt":"Lila 🟣","expected":"lila","hint":"Mischung aus Rot und Blau","hint_translation":"Mix of red and blue"},{"prompt":"Gelb 🟡","expected":"gelb","hint":"Farbe der Sonne","hint_translation":"Color of the sun"},{"prompt":"Lila 🟣","expected":"lila","hint":"Farbe der Lavendelblüten","hint_translation":"Color of lavender flowers"},{"prompt":"Orange 🟠","expected":"orange","hint":"Farbe der Orangenfrucht","hint_translation":"Color of the orange fruit"},{"prompt":"Braun 🟤","expected":"braun","hint":"Farbe der Erde","hint_translation":"Color of the earth"},{"prompt":"Rosa 🌸","expected":"rosa","hint":"Farbe der Rosen","hint_translation":"Color of roses"},{"prompt":"Grau ⚪","expected":"grau","hint":"Farbe des Nebels","hint_translation":"Color of fog"},{"prompt":"Schwarz ⚫","expected":"schwarz","hint":"Farbe der Nacht","hint_translation":"Color of the night"},{"prompt":"Weiß ⚪","expected":"weiß","hint":"Farbe des Schnees","hint_translation":"Color of snow"},{"prompt":"Türkis 🟢","expected":"türkis","hint":"Farbe des tropischen Wassers","hint_translation":"Color of tropical water"},{"prompt":"Beige 🟤","expected":"beige","hint":"Farbe der Sandstrände","hint_translation":"Color of sandy beaches"},{"prompt":"Violett 🟣","expected":"violett","hint":"Farbe des Abendhimmels","hint_translation":"Color of the evening sky"},{"prompt":"Gold 🟡","expected":"gold","hint":"Farbe des Goldes","hint_translation":"Color of gold"},{"prompt":"Silber ⚪","expected":"silber","hint":"Farbe des Silbers","hint_translation":"Color of silver"},{"prompt":"Mintgrün 🟢","expected":"mintgrün","hint":"Farbe der Minzpflanze","hint_translation":"Color of the mint plant"},{"prompt":"Kobaltblau 🔵","expected":"kobaltblau","hint":"Farbe des Kobalts","hint_translation":"Color of cobalt"},{"prompt":"Mahagoni 🟤","expected":"mahagoni","hint":"Farbe des Mahagoniholzes","hint_translation":"Color of mahogany wood"}]}', 4),

('de', 'A1', 'speaking', 'Tiernamen', 'Animal Names', 'Sag die Namen der Tiere laut', 'Say the names of animals out loud',
'{"type":"speak_and_compare","instructions":"Sag den Tiernamen, wenn du das Bild siehst!","exercises":[{"prompt":"🐱 Welches Tier ist das?","expected":"katze","hint":"Es sagt miau","hint_translation":"It says meow"},{"prompt":"🐶 Welches Tier ist das?","expected":"hund","hint":"Es sagt wuff","hint_translation":"It says woof"},{"prompt":"🐦 Welches Tier ist das?","expected":"vogel","hint":"Es kann fliegen","hint_translation":"It can fly"},{"prompt":"🐟 Welches Tier ist das?","expected":"fisch","hint":"Es schwimmt","hint_translation":"It swims"},{"prompt":"🐘 Welches Tier ist das?","expected":"elefant","hint":"Sehr groß mit Rüssel","hint_translation":"Very large with a trunk"},{"prompt":"🐰 Welches Tier ist das?","expected":"kaninchen","hint":"Es hat lange Ohren","hint_translation":"It has long ears"},{"prompt":"🐴 Welches Tier ist das?","expected":"pferd","hint":"Es kann schnell laufen","hint_translation":"It can run fast"},{"prompt":"🐘 Welches Tier ist das?","expected":"elefant","hint":"Es hat einen langen Rüssel","hint_translation":"It has a long trunk"},{"prompt":"🐍 Welches Tier ist das?","expected":"schlange","hint":"Es hat keine Beine","hint_translation":"It has no legs"},{"prompt":"🦁 Welches Tier ist das?","expected":"löwe","hint":"Es ist der König der Tiere","hint_translation":"It is the king of the animals"},{"prompt":"🐢 Welches Tier ist das?","expected":"schildkröte","hint":"Es hat einen Panzer","hint_translation":"It has a shell"},{"prompt":"🦊 Welches Tier ist das?","expected":"fuchs","hint":"Es ist schlau und hat einen buschigen Schwanz","hint_translation":"It is clever and has a bushy tail"},{"prompt":"🐦 Welches Tier ist das?","expected":"papagei","hint":"Es kann sprechen","hint_translation":"It can speak"},{"prompt":"🐿️ Welches Tier ist das?","expected":"eichhörnchen","hint":"Es sammelt Nüsse","hint_translation":"It collects nuts"},{"prompt":"🐻 Welches Tier ist das?","expected":"bär","hint":"Es liebt Honig","hint_translation":"It loves honey"},{"prompt":"🐷 Welches Tier ist das?","expected":"schwein","hint":"Es sagt oink","hint_translation":"It says oink"},{"prompt":"🐮 Welches Tier ist das?","expected":"kuh","hint":"Es gibt Milch","hint_translation":"It gives milk"},{"prompt":"🦒 Welches Tier ist das?","expected":"giraffe","hint":"Es hat einen langen Hals","hint_translation":"It has a long neck"},{"prompt":"🐥 Welches Tier ist das?","expected":"küken","hint":"Es kommt aus einem Ei","hint_translation":"It comes from an egg"},{"prompt":"🦙 Welches Tier ist das?","expected":"lama","hint":"Es hat weiches Fell","hint_translation":"It has soft fur"}]}', 5);

