INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'reading', 'Wort-Zuordnung', 'Word Matching', 'Einfache Wörter lesen und Bildern zuordnen', 'Read simple words and match with pictures',
'{"type":"read_and_match","instructions":"Lies das Wort und wähle das passende Bild.","exercises":[{"word":"Katze","options":["🐱","🐶","🐟","🐦"],"correct":0},{"word":"Sonne","options":["🌙","⭐","☀️","🌧️"],"correct":2},{"word":"Buch","options":["📱","📖","🎮","🎸"],"correct":1},{"word":"Apfel","options":["🍌","🍇","🍎","🍊"],"correct":2},{"word":"Haus","options":["🏫","🏠","🏥","🏪"],"correct":1},{"word":"Hund","options":["🐶","🐱","🐰","🐹"],"correct":0},{"word":"Auto","options":["🚗","🚲","✈️","🚀"],"correct":0},{"word":"Blume","options":["🌹","🌲","🍁","🌻"],"correct":0},{"word":"Tisch","options":["🪑","🛏️","🪄","🪞"],"correct":1},{"word":"Apfel","options":["🍌","🍏","🍉","🍓"],"correct":1},{"word":"Haus","options":["🏠","🏢","🏡","🏰"],"correct":0},{"word":"Käse","options":["🍫","🧀","🍕","🍔"],"correct":1},{"word":"Fisch","options":["🐡","🐢","🐇","🐍"],"correct":0},{"word":"Zug","options":["🚆","🚋","🚄","🚉"],"correct":0},{"word":"Stern","options":["🌟","☁️","🌈","🌕"],"correct":0},{"word":"Kopf","options":["🦵","👋","🧠","👤"],"correct":2},{"word":"Ball","options":["⚽","🏀","🎾","🏈"],"correct":0},{"word":"Bett","options":["🛏️","🛋️","🪑","🛀"],"correct":0},{"word":"Gitarre","options":["🎸","🎻","🎺","🥁"],"correct":0},{"word":"Kamera","options":["📷","📸","📹","💻"],"correct":1}]}', 1),

('de', 'A1', 'reading', 'Einfache Sätze', 'Simple Sentences', 'Kurze Sätze lesen und verstehen', 'Read and understand short sentences',
'{"type":"read_and_choose","instructions":"Lies den Satz und wähle die Bedeutung.","exercises":[{"sentence":"Die Katze ist auf der Matte.","question":"Wo ist die Katze?","options":["Auf der Matte","Unter dem Tisch","In der Kiste","Auf dem Bett"],"correct":0},{"sentence":"Ich habe zwei Äpfel.","question":"Wie viele Äpfel?","options":["Eins","Zwei","Drei","Vier"],"correct":1},{"sentence":"Die Sonne ist gelb.","question":"Welche Farbe hat die Sonne?","options":["Rot","Blau","Gelb","Grün"],"correct":2},{"sentence":"Mein Hund ist groß.","question":"Was ist groß?","options":["Die Katze","Der Vogel","Der Fisch","Der Hund"],"correct":3},{"sentence":"Sie mag Eiscreme.","question":"Was mag sie?","options":["Eiscreme","Pizza","Kuchen","Brot"],"correct":0},{"sentence":"Der Hund bellt laut.","question":"Was macht der Hund?","options":["Er schläft","Er bellt","Er frisst","Er spielt"],"correct":1},{"sentence":"Die Blume ist rot.","question":"Welche Farbe hat die Blume?","options":["Gelb","Rot","Blau","Weiß"],"correct":1},{"sentence":"Ich trinke Wasser.","question":"Was trinke ich?","options":["Saft","Wasser","Milch","Tee"],"correct":1},{"sentence":"Das Auto ist schnell.","question":"Wie ist das Auto?","options":["Langsam","Schnell","Alt","Neu"],"correct":1},{"sentence":"Der Tisch ist aus Holz.","question":"Woraus ist der Tisch?","options":["Aus Glas","Aus Plastik","Aus Holz","Aus Metall"],"correct":2},{"sentence":"Die Uhr zeigt drei Uhr.","question":"Wie viel Uhr ist es?","options":["Zwei Uhr","Drei Uhr","Vier Uhr","Fünf Uhr"],"correct":1},{"sentence":"Die Kinder spielen im Garten.","question":"Wo spielen die Kinder?","options":["Im Garten","In der Schule","Im Haus","Auf dem Spielplatz"],"correct":0},{"sentence":"Die Vögel fliegen hoch.","question":"Was machen die Vögel?","options":["Sie fliegen","Sie singen","Sie essen","Sie schlafen"],"correct":0},{"sentence":"Ich lese ein Buch.","question":"Was mache ich?","options":["Ich schreibe","Ich lese","Ich zeichne","Ich spiele"],"correct":1},{"sentence":"Das Wetter ist schön.","question":"Wie ist das Wetter?","options":["Schlecht","Schön","Kalt","Warm"],"correct":1},{"sentence":"Die Fische schwimmen im Wasser.","question":"Wo schwimmen die Fische?","options":["Im Wasser","In der Luft","Auf dem Land","In der Sonne"],"correct":0},{"sentence":"Mein Bruder spielt Fußball.","question":"Was macht mein Bruder?","options":["Er liest","Er spielt Fußball","Er schwimmt","Er kocht"],"correct":1},{"sentence":"Die Torte schmeckt süß.","question":"Wie schmeckt die Torte?","options":["Sauer","Bitter","Süß","Salzig"],"correct":2},{"sentence":"Die Schule beginnt um acht Uhr.","question":"Wann beginnt die Schule?","options":["Um sieben Uhr","Um acht Uhr","Um neun Uhr","Um zehn Uhr"],"correct":1},{"sentence":"Ich habe einen Hund.","question":"Was habe ich?","options":["Eine Katze","Einen Hund","Ein Kaninchen","Ein Pferd"],"correct":1}]}', 2),

('de', 'A1', 'reading', 'Lückentext', 'Fill in the Blanks', 'Vervollständige einfache Sätze', 'Complete simple sentences',
'{"type":"fill_blank","instructions":"Lies den Satz und wähle das fehlende Wort.","exercises":[{"sentence":"Der Himmel ist ___.","options":["blau","groß","schnell","heiß"],"correct":0},{"sentence":"Ich ___ ein Schüler.","options":["ist","bin","sind","sein"],"correct":1},{"sentence":"Sie ___ zur Schule.","options":["gehe","geht","gehen","gegangen"],"correct":1},{"sentence":"Wir haben ___ Hunde.","options":["ein","eine","zwei","der"],"correct":2},{"sentence":"Das ist ___ Apfel.","options":["ein","eine","der","zwei"],"correct":0},{"sentence":"Das Wasser ist ___.","options":["kalt","schnell","hoch","dunkel"],"correct":0},{"sentence":"Ich ___ ein Buch.","options":["lese","liest","lesen","lesen"],"correct":0},{"sentence":"Er ___ Fußball.","options":["spielen","spielt","spiel","gespielt"],"correct":1},{"sentence":"Wir ___ nach Hause.","options":["gehe","gehen","geht","gegangen"],"correct":1},{"sentence":"Die Katze ist ___.","options":["schwarz","schnell","lang","schöner"],"correct":0},{"sentence":"Du ___ freundlich.","options":["bist","ist","sind","sein"],"correct":0},{"sentence":"Das Kind ___ spielt im Park.","options":["gerade","immer","nie","auch"],"correct":0},{"sentence":"Ich ___ eine Tasse Kaffee.","options":["trinke","trinkt","trink","trunken"],"correct":0},{"sentence":"Sie ___ sehr schnell.","options":["läuft","laufen","lauf","lief"],"correct":0},{"sentence":"Der Tisch ist ___.","options":["neu","alt","schmutzig","klein"],"correct":0},{"sentence":"Wir ___ im Restaurant.","options":["essen","isst","essen","gegessen"],"correct":0},{"sentence":"Das Wetter ist ___.","options":["schön","traurig","schnell","stark"],"correct":0},{"sentence":"Er ___ dich sehr.","options":["mag","möchte","liebt","sieht"],"correct":0},{"sentence":"Wir ___ zusammen.","options":["spielen","spielt","spiel","gegangen"],"correct":0},{"sentence":"Die Blume ist ___.","options":["bunt","stark","lang","schmutzig"],"correct":0}]}', 3),

('de', 'A1', 'reading', 'Richtig oder Falsch', 'True or False', 'Lies und entscheide, ob die Aussagen stimmen', 'Read and decide if the statements are correct',
'{"type":"true_false","instructions":"Lies den Satz. Richtig oder Falsch?","exercises":[{"statement":"Eine Katze kann fliegen.","correct":false,"explanation":"Katzen können nicht fliegen. Vögel können fliegen!"},{"statement":"Die Sonne ist heiß.","correct":true,"explanation":"Ja! Die Sonne ist sehr heiß."},{"statement":"Fische leben im Wasser.","correct":true,"explanation":"Richtig! Fische leben im Wasser."},{"statement":"Eiscreme ist heiß.","correct":false,"explanation":"Nein! Eiscreme ist kalt und lecker."},{"statement":"Menschen haben zwei Augen.","correct":true,"explanation":"Ja! Wir haben zwei Augen."},{"statement":"Ein Elefant kann gut schwimmen.","correct":true,"explanation":"Ja! Elefanten sind überraschend gute Schwimmer."},{"statement":"Eine Banane ist eine Art Gemüse.","correct":false,"explanation":"Falsch! Eine Banane ist eine Frucht."},{"statement":"Die Erde ist der dritte Planet von der Sonne.","correct":true,"explanation":"Richtig! Die Erde ist der dritte Planet im Sonnensystem."},{"statement":"Ein Mensch kann ohne Wasser mehrere Wochen überleben.","correct":false,"explanation":"Falsch! Menschen können nur wenige Tage ohne Wasser überleben."},{"statement":"Schnecken haben ein Gehäuse.","correct":true,"explanation":"Richtig! Schnecken haben oft ein schützendes Gehäuse."},{"statement":"Ein Känguru kann rückwärts springen.","correct":false,"explanation":"Falsch! Kängurus können nicht rückwärts springen."},{"statement":"Die meisten Vögel können nicht schwimmen.","correct":false,"explanation":"Falsch! Einige Vögel, wie Pinguine, können sehr gut schwimmen."},{"statement":"Ein Flugzeug braucht Treibstoff, um zu fliegen.","correct":true,"explanation":"Richtig! Flugzeuge benötigen Treibstoff, um in die Luft zu gelangen."},{"statement":"Die Hauptstadt von Deutschland ist Berlin.","correct":true,"explanation":"Ja! Berlin ist die Hauptstadt Deutschlands."},{"statement":"Ein Zebra ist ein Haustier.","correct":false,"explanation":"Falsch! Ein Zebra ist ein Wildtier, kein Haustier."},{"statement":"Der menschliche Körper hat 206 Knochen.","correct":true,"explanation":"Richtig! Ein Erwachsener hat in der Regel 206 Knochen."},{"statement":"Fledermäuse sind keine Säugetiere.","correct":false,"explanation":"Falsch! Fledermäuse sind Säugetiere."},{"statement":"Wasser gefriert bei 0 Grad Celsius.","correct":true,"explanation":"Richtig! Wasser gefriert bei 0 Grad Celsius."},{"statement":"Ein Kühlschrank kann Dinge kochen.","correct":false,"explanation":"Falsch! Ein Kühlschrank kühlt, aber kocht nicht."},{"statement":"Bienen produzieren Honig.","correct":true,"explanation":"Ja! Bienen sind bekannt dafür, Honig zu produzieren."}]}', 4),

('de', 'A1', 'reading', 'Wortgruppen', 'Word Groups', 'Verwandte Wörter zusammenfügen', 'Assemble related words',
'{"type":"read_and_match","instructions":"Lies das Wort und wähle die passende Gruppe.","exercises":[{"word":"Hund","options":["Tiere","Essen","Farben","Zahlen"],"correct":0},{"word":"Rot","options":["Tiere","Essen","Farben","Zahlen"],"correct":2},{"word":"Apfel","options":["Tiere","Essen","Farben","Zahlen"],"correct":1},{"word":"Drei","options":["Tiere","Essen","Farben","Zahlen"],"correct":3},{"word":"Banane","options":["Tiere","Essen","Farben","Zahlen"],"correct":1},{"word":"Katze","options":["Tiere","Essen","Farben","Zahlen"],"correct":0},{"word":"Blau","options":["Tiere","Essen","Farben","Zahlen"],"correct":2},{"word":"Banane","options":["Tiere","Essen","Farben","Zahlen"],"correct":1},{"word":"Drei","options":["Tiere","Essen","Farben","Zahlen"],"correct":3},{"word":"Vogel","options":["Tiere","Essen","Farben","Zahlen"],"correct":0},{"word":"Grün","options":["Tiere","Essen","Farben","Zahlen"],"correct":2},{"word":"Karotte","options":["Tiere","Essen","Farben","Zahlen"],"correct":1},{"word":"Fünf","options":["Tiere","Essen","Farben","Zahlen"],"correct":3},{"word":"Pferd","options":["Tiere","Essen","Farben","Zahlen"],"correct":0},{"word":"Gelb","options":["Tiere","Essen","Farben","Zahlen"],"correct":2},{"word":"Tomate","options":["Tiere","Essen","Farben","Zahlen"],"correct":1},{"word":"Sechs","options":["Tiere","Essen","Farben","Zahlen"],"correct":3},{"word":"Schaf","options":["Tiere","Essen","Farben","Zahlen"],"correct":0},{"word":"Orange","options":["Tiere","Essen","Farben","Zahlen"],"correct":2},{"word":"Birne","options":["Tiere","Essen","Farben","Zahlen"],"correct":1}]}', 5);

