INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'writing', 'Buchstaben tippen', 'Typing Letters', 'Einzelne Buchstaben tippen üben', 'Practice typing individual letters',
'{"type":"type_word","instructions":"Tippe den Buchstaben, den du siehst.","exercises":[{"prompt":"Tippe: A","expected":"A","hint":"Der erste Buchstabe","hint_translation":"The first letter"},{"prompt":"Tippe: B","expected":"B","hint":"Der zweite Buchstabe","hint_translation":"The second letter"},{"prompt":"Tippe: C","expected":"C","hint":"Das Wort Clown beginnt damit","hint_translation":"The word Clown starts with this"},{"prompt":"Tippe: D","expected":"D","hint":"Das Wort Dino beginnt damit","hint_translation":"The word Dino starts with this"},{"prompt":"Tippe: E","expected":"E","hint":"Das Wort Elefant beginnt damit","hint_translation":"The word Elephant starts with this"},{"prompt":"Tippe: D","expected":"D","hint":"Der Buchstabe nach C","hint_translation":"The letter after C"},{"prompt":"Tippe: E","expected":"E","hint":"Das Wort Elefant beginnt damit","hint_translation":"The word Elephant starts with this"},{"prompt":"Tippe: F","expected":"F","hint":"Der Buchstabe, der in Flugzeug vorkommt","hint_translation":"The letter that is in airplane"},{"prompt":"Tippe: G","expected":"G","hint":"Der erste Buchstabe von Geschenk","hint_translation":"The first letter of gift"},{"prompt":"Tippe: H","expected":"H","hint":"Das Wort Haus beginnt damit","hint_translation":"The word House starts with this"},{"prompt":"Tippe: I","expected":"I","hint":"Der Buchstabe in dem Wort Insel","hint_translation":"The letter in the word Island"},{"prompt":"Tippe: J","expected":"J","hint":"Der erste Buchstabe von Junge","hint_translation":"The first letter of Boy"},{"prompt":"Tippe: K","expected":"K","hint":"Der Buchstabe für Katze","hint_translation":"The letter for Cat"},{"prompt":"Tippe: L","expected":"L","hint":"Das Wort Lampe beginnt damit","hint_translation":"The word Lamp starts with this"},{"prompt":"Tippe: M","expected":"M","hint":"Der Buchstabe in dem Wort Maus","hint_translation":"The letter in the word Mouse"},{"prompt":"Tippe: N","expected":"N","hint":"Der Buchstabe nach M","hint_translation":"The letter after M"},{"prompt":"Tippe: O","expected":"O","hint":"Das Wort Orange beginnt damit","hint_translation":"The word Orange starts with this"},{"prompt":"Tippe: P","expected":"P","hint":"Der erste Buchstabe von Pferd","hint_translation":"The first letter of Horse"},{"prompt":"Tippe: Q","expected":"Q","hint":"Der Buchstabe, der in der Frage vorkommt","hint_translation":"The letter that is in the question"},{"prompt":"Tippe: R","expected":"R","hint":"Das Wort Rose beginnt damit","hint_translation":"The word Rose starts with this"}]}', 1),

('de', 'A1', 'writing', 'Wörter buchstabieren', 'Spelling Words', 'Kurze Wörter richtig schreiben', 'Write short words correctly',
'{"type":"type_word","instructions":"Höre das Wort und tippe es richtig.","exercises":[{"prompt":"katze","expected":"katze","hint":"🐱 Fünf Buchstaben, beginnt mit K","hint_translation":"Five letters, starts with K"},{"prompt":"hund","expected":"hund","hint":"🐶 Vier Buchstaben, beginnt mit H","hint_translation":"Four letters, starts with H"},{"prompt":"sonne","expected":"sonne","hint":"☀️ Fünf Buchstaben, beginnt mit S","hint_translation":"Five letters, starts with S"},{"prompt":"rot","expected":"rot","hint":"🔴 Drei Buchstaben, eine Farbe","hint_translation":"Three letters, a color"},{"prompt":"groß","expected":"groß","hint":"Das Gegenteil von klein","hint_translation":"The opposite of small"},{"prompt":"vogel","expected":"vogel","hint":"🐦 Fünf Buchstaben, beginnt mit V","hint_translation":"Five letters, starts with V"},{"prompt":"fisch","expected":"fisch","hint":"🐟 Fünf Buchstaben, beginnt mit F","hint_translation":"Five letters, starts with F"},{"prompt":"blume","expected":"blume","hint":"🌸 Fünf Buchstaben, beginnt mit B","hint_translation":"Five letters, starts with B"},{"prompt":"tisch","expected":"tisch","hint":"🪑 Vier Buchstaben, beginnt mit T","hint_translation":"Four letters, starts with T"},{"prompt":"auto","expected":"auto","hint":"🚗 Vier Buchstaben, beginnt mit A","hint_translation":"Four letters, starts with A"},{"prompt":"stuhl","expected":"stuhl","hint":"🪑 Fünf Buchstaben, beginnt mit S","hint_translation":"Five letters, starts with S"},{"prompt":"haus","expected":"haus","hint":"🏠 Vier Buchstaben, beginnt mit H","hint_translation":"Four letters, starts with H"},{"prompt":"baum","expected":"baum","hint":"🌳 Vier Buchstaben, beginnt mit B","hint_translation":"Four letters, starts with B"},{"prompt":"freund","expected":"freund","hint":"👫 Sechs Buchstaben, beginnt mit F","hint_translation":"Six letters, starts with F"},{"prompt":"kind","expected":"kind","hint":"👶 Vier Buchstaben, beginnt mit K","hint_translation":"Four letters, starts with K"},{"prompt":"karte","expected":"karte","hint":"🗺️ Fünf Buchstaben, beginnt mit K","hint_translation":"Five letters, starts with K"},{"prompt":"licht","expected":"licht","hint":"💡 Fünf Buchstaben, beginnt mit L","hint_translation":"Five letters, starts with L"},{"prompt":"schnee","expected":"schnee","hint":"❄️ Sechs Buchstaben, beginnt mit S","hint_translation":"Six letters, starts with S"},{"prompt":"tür","expected":"tür","hint":"🚪 Drei Buchstaben, beginnt mit T","hint_translation":"Three letters, starts with T"},{"prompt":"wasser","expected":"wasser","hint":"💧 Sechs Buchstaben, beginnt mit W","hint_translation":"Six letters, starts with W"}]}', 2),

('de', 'A1', 'writing', 'Worträtsel', 'Word Puzzles', 'Buchstaben ordnen, um Wörter zu bilden', 'Arrange letters to form words',
'{"type":"unscramble","instructions":"Die Buchstaben sind vertauscht! Tippe das richtige Wort.","exercises":[{"scrambled":"atkez","expected":"katze","hint":"🐱 Ein Haustier, das miau sagt","hint_translation":"A pet that says meow"},{"scrambled":"neons","expected":"sonne","hint":"☀️ Sie scheint am Himmel","hint_translation":"It shines in the sky"},{"scrambled":"faple","expected":"apfel","hint":"🍎 Eine rote Frucht","hint_translation":"A red fruit"},{"scrambled":"hchu","expected":"buch","hint":"📖 Man kann es lesen","hint_translation":"You can read it"},{"scrambled":"chisf","expected":"fisch","hint":"🐟 Er schwimmt im Wasser","hint_translation":"It swims in water"},{"scrambled":"gertis","expected":"sitzge","hint":"🪑 Etwas, auf dem man sitzt","hint_translation":"Something you sit on"},{"scrambled":"imngan","expected":"naming","hint":"📞 Man benutzt es, um jemanden zu kontaktieren","hint_translation":"You use it to contact someone"},{"scrambled":"rkeaw","expected":"werak","hint":"🌊 Etwas, das im Wasser schwimmt","hint_translation":"Something that swims in the water"},{"scrambled":"tscah","expected":"schat","hint":"📖 Eine Geschichte oder ein Text","hint_translation":"A story or a text"},{"scrambled":"luceh","expected":"leuch","hint":"💡 Etwas, das Licht gibt","hint_translation":"Something that gives light"},{"scrambled":"lraef","expected":"feral","hint":"🦁 Ein Tier, das oft in der Wildnis lebt","hint_translation":"An animal that often lives in the wild"},{"scrambled":"ogtca","expected":"gacto","hint":"🐶 Ein beliebtes Haustier","hint_translation":"A popular pet"},{"scrambled":"brenla","expected":"banler","hint":"🎨 Ein Werkzeug zum Zeichnen","hint_translation":"A tool for drawing"},{"scrambled":"zmearv","expected":"vrmaze","hint":"🧩 Ein Spiel, das man lösen kann","hint_translation":"A game you can solve"},{"scrambled":"epcih","expected":"chip","hint":"🍟 Ein Snack aus Kartoffeln","hint_translation":"A snack made from potatoes"},{"scrambled":"tbenra","expected":"banter","hint":"🌍 Ein Ort, an dem Menschen leben","hint_translation":"A place where people live"},{"scrambled":"mcaht","expected":"mchat","hint":"🖥️ Ein Weg, um online zu kommunizieren","hint_translation":"A way to communicate online"},{"scrambled":"rheo","expected":"rohe","hint":"🍃 Eine Pflanze, die oft in Gärten wächst","hint_translation":"A plant that often grows in gardens"},{"scrambled":"emgni","expected":"genim","hint":"🔑 Ein Werkzeug, um Türen zu öffnen","hint_translation":"A tool to open doors"},{"scrambled":"rdeilf","expected":"filder","hint":"⚙️ Etwas, das man zum Arbeiten benutzt","hint_translation":"Something you use for working"}]}', 3),

('de', 'A1', 'writing', 'Wort vervollständigen', 'Completing Words', 'Fehlende Buchstaben einfüllen', 'Fill in missing letters',
'{"type":"fill_letters","instructions":"Einige Buchstaben fehlen. Tippe das ganze Wort.","exercises":[{"partial":"k_tze","expected":"katze","hint":"🐱 Ein flauschiges Tier","hint_translation":"A fluffy animal"},{"partial":"h_nd","expected":"hund","hint":"🐶 Ein treues Tier","hint_translation":"A faithful animal"},{"partial":"b__h","expected":"buch","hint":"📖 Man liest darin","hint_translation":"You read in it"},{"partial":"h__s","expected":"haus","hint":"🏠 Wo man wohnt","hint_translation":"Where you live"},{"partial":"bl__e","expected":"blume","hint":"🌸 Wächst im Garten","hint_translation":"Grows in the garden"},{"partial":"f__r","expected":"fisch","hint":"🐟 Lebt im Wasser","hint_translation":"Lives in the water"},{"partial":"v__l","expected":"vogel","hint":"🐦 Kann fliegen","hint_translation":"Can fly"},{"partial":"s__l","expected":"stuhl","hint":"🪑 Darauf sitzt man","hint_translation":"You sit on it"},{"partial":"m__r","expected":"mauer","hint":"🧱 Teil eines Hauses","hint_translation":"Part of a house"},{"partial":"t__p","expected":"topf","hint":"🍲 Zum Kochen","hint_translation":"Used for cooking"},{"partial":"l__be","expected":"lampe","hint":"💡 Gibt Licht","hint_translation":"Provides light"},{"partial":"w__n","expected":"wagen","hint":"🚗 Ein Fortbewegungsmittel","hint_translation":"A means of transportation"},{"partial":"g__n","expected":"garten","hint":"🌳 Draußen mit Pflanzen","hint_translation":"Outside with plants"},{"partial":"t__r","expected":"tisch","hint":"🍽️ Darauf isst man","hint_translation":"You eat on it"},{"partial":"b__d","expected":"brot","hint":"🍞 Ein Grundnahrungsmittel","hint_translation":"A staple food"},{"partial":"f__n","expected":"fahne","hint":"🚩 Ein Symbol eines Landes","hint_translation":"A symbol of a country"},{"partial":"s__n","expected":"sonne","hint":"☀️ Gibt Licht und Wärme","hint_translation":"Provides light and warmth"},{"partial":"g__t","expected":"gift","hint":"☠️ Kann gefährlich sein","hint_translation":"Can be dangerous"},{"partial":"h__s","expected":"haus","hint":"🏠 Ein Zuhause","hint_translation":"A home"},{"partial":"a__f","expected":"apfel","hint":"🍏 Eine Frucht","hint_translation":"A fruit"},{"partial":"k__n","expected":"kuchen","hint":"🎂 Ein Dessert","hint_translation":"A dessert"}]}', 4),

('de', 'A1', 'writing', 'Satz schreiben', 'Writing Sentences', 'Einfache Sätze genau abtippen', 'Type simple sentences exactly',
'{"type":"copy_sentence","instructions":"Lies den Satz und tippe ihn genau so.","exercises":[{"sentence":"Ich bin glücklich.","expected":"Ich bin glücklich.","hint":"Drei Wörter und ein Punkt","hint_translation":"Three words and a period"},{"sentence":"Die Katze ist groß.","expected":"Die Katze ist groß.","hint":"Vier Wörter über eine Katze","hint_translation":"Four words about a cat"},{"sentence":"Ich mag Rot.","expected":"Ich mag Rot.","hint":"Drei Wörter über eine Farbe","hint_translation":"Three words about a color"},{"sentence":"Sie hat einen Hund.","expected":"Sie hat einen Hund.","hint":"Vier Wörter über ein Haustier","hint_translation":"Four words about a pet"},{"sentence":"Wir gehen zur Schule.","expected":"Wir gehen zur Schule.","hint":"Vier Wörter über einen Ort","hint_translation":"Four words about a place"},{"sentence":"Das Wetter ist schön.","expected":"Das Wetter ist schön.","hint":"Fünf Wörter über das Wetter","hint_translation":"Five words about the weather"},{"sentence":"Ich trinke Wasser.","expected":"Ich trinke Wasser.","hint":"Drei Wörter über ein Getränk","hint_translation":"Three words about a drink"},{"sentence":"Mein Hund ist freundlich.","expected":"Mein Hund ist freundlich.","hint":"Fünf Wörter über einen Hund","hint_translation":"Five words about a dog"},{"sentence":"Die Blumen blühen im Frühling.","expected":"Die Blumen blühen im Frühling.","hint":"Sechs Wörter über Blumen","hint_translation":"Six words about flowers"},{"sentence":"Ich liebe Schokolade.","expected":"Ich liebe Schokolade.","hint":"Drei Wörter über eine Süßigkeit","hint_translation":"Three words about a sweet"},{"sentence":"Wir gehen ins Kino.","expected":"Wir gehen ins Kino.","hint":"Fünf Wörter über einen Ausflug","hint_translation":"Five words about an outing"},{"sentence":"Die Vögel singen morgens.","expected":"Die Vögel singen morgens.","hint":"Fünf Wörter über Vögel","hint_translation":"Five words about birds"},{"sentence":"Es regnet heute.","expected":"Es regnet heute.","hint":"Drei Wörter über das Wetter","hint_translation":"Three words about the weather"},{"sentence":"Mein Lieblingsbuch ist spannend.","expected":"Mein Lieblingsbuch ist spannend.","hint":"Sechs Wörter über ein Buch","hint_translation":"Six words about a book"},{"sentence":"Ich esse gerne Pizza.","expected":"Ich esse gerne Pizza.","hint":"Fünf Wörter über Essen","hint_translation":"Five words about food"},{"sentence":"Wir haben einen schönen Garten.","expected":"Wir haben einen schönen Garten.","hint":"Sechs Wörter über einen Garten","hint_translation":"Six words about a garden"},{"sentence":"Die Kinder spielen im Park.","expected":"Die Kinder spielen im Park.","hint":"Fünf Wörter über Kinder","hint_translation":"Five words about children"},{"sentence":"Ich gehe gerne schwimmen.","expected":"Ich gehe gerne schwimmen.","hint":"Fünf Wörter über eine Aktivität","hint_translation":"Five words about an activity"},{"sentence":"Mein Freund ist sehr nett.","expected":"Mein Freund ist sehr nett.","hint":"Fünf Wörter über einen Freund","hint_translation":"Five words about a friend"},{"sentence":"Die Schule beginnt um acht.","expected":"Die Schule beginnt um acht.","hint":"Fünf Wörter über die Schule","hint_translation":"Five words about school"},{"sentence":"Ich mag die Musik.","expected":"Ich mag die Musik.","hint":"Drei Wörter über Musik","hint_translation":"Three words about music"}]}', 5);

