INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A2', 'listening', 'Mein Alltag', 'My Daily Routine', 'Aktivitäten im Tagesablauf hören', 'Listen to activities in the daily routine',
'{"type":"listen_and_choose","instructions":"Höre den Satz und antworte.","exercises":[{"prompt":"Ich stehe jeden Morgen um sieben Uhr auf.","question":"Wann wacht die Person auf?","options":["6 Uhr","7 Uhr","8 Uhr","9 Uhr"],"correct":1},{"prompt":"Nach dem Frühstück putze ich meine Zähne.","question":"Was passiert nach dem Frühstück?","options":["Schlafen","Spielen","Zähne putzen","Fernsehen"],"correct":2},{"prompt":"Ich esse um halb eins zu Mittag.","question":"Wann gibt es Mittagessen?","options":["11:00","12:00","12:30","1:30"],"correct":2},{"prompt":"Am Abend mache ich Hausaufgaben.","question":"Wann werden die Hausaufgaben gemacht?","options":["Morgens","Mittags","Abends","Nachts"],"correct":2},{"prompt":"Ich gehe um neun Uhr ins Bett.","question":"Wann ist Schlafenszeit?","options":["8 Uhr","9 Uhr","10 Uhr","11 Uhr"],"correct":1},{"prompt":"Ich gehe jeden Tag um acht Uhr zur Schule.","question":"Wann geht die Person zur Schule?","options":["7 Uhr","8 Uhr","9 Uhr","10 Uhr"],"correct":1},{"prompt":"Am Wochenende spiele ich oft Fußball.","question":"Was macht die Person am Wochenende?","options":["Schlafen","Fußball spielen","Fernsehen","Lesen"],"correct":1},{"prompt":"Ich trinke jeden Morgen Kaffee.","question":"Was trinkt die Person jeden Morgen?","options":["Tee","Kaffee","Saft","Wasser"],"correct":1},{"prompt":"Ich mache jeden Abend meine Hausaufgaben.","question":"Was macht die Person jeden Abend?","options":["Hausaufgaben","Einkaufen","Kochen","Spielen"],"correct":0},{"prompt":"Ich gehe oft ins Kino am Freitagabend.","question":"Wann geht die Person ins Kino?","options":["Montag","Freitagabend","Sonntagmorgen","Samstagnachmittag"],"correct":1},{"prompt":"Ich höre Musik, während ich arbeite.","question":"Was macht die Person, während sie arbeitet?","options":["Schläft","Musik hören","Essen","Lesen"],"correct":1},{"prompt":"Wir essen abends immer zusammen.","question":"Wann essen sie zusammen?","options":["Morgens","Mittags","Abends","Nachts"],"correct":2},{"prompt":"Ich gehe jeden Sonntag in die Kirche.","question":"An welchem Tag geht die Person in die Kirche?","options":["Freitag","Samstag","Sonntag","Montag"],"correct":2},{"prompt":"Ich lese jeden Abend ein Buch.","question":"Was macht die Person jeden Abend?","options":["Schaut Fernsehen","Geht spazieren","Liest ein Buch","Spielt"],"correct":2},{"prompt":"Ich kaufe einmal pro Woche ein.","question":"Wie oft kauft die Person ein?","options":["Jeden Tag","Einmal pro Woche","Zweimal pro Woche","Monatlich"],"correct":1},{"prompt":"Ich mache jeden Morgen Sport.","question":"Was macht die Person jeden Morgen?","options":["Sport","Schlafen","Essen","Arbeiten"],"correct":0},{"prompt":"Ich telefoniere jeden Abend mit meiner Freundin.","question":"Wann telefoniert die Person?","options":["Morgens","Nachmittags","Abends","Nacht"],"correct":2},{"prompt":"Ich backe am Sonntag einen Kuchen.","question":"Was macht die Person am Sonntag?","options":["Einkaufen","Backen","Spielen","Schlafen"],"correct":1},{"prompt":"Ich putze jeden Samstag das Haus.","question":"Wann putzt die Person das Haus?","options":["Montag","Freitag","Samstag","Sonntag"],"correct":2}]}', 1),

('de', 'A2', 'speaking', 'Im Restaurant', 'At the Restaurant', 'Übe, Essen zu bestellen', 'Practice ordering food',
'{"type":"speak_and_compare","instructions":"Stell dir vor, du bist im Restaurant.","exercises":[{"prompt":"Die Speisekarte, bitte.","expected":"die speisekarte bitte","hint":"Nach der Karte fragen"},{"prompt":"Ich möchte eine Pizza, bitte.","expected":"ich möchte eine pizza bitte","hint":"Essen bestellen"},{"prompt":"Ein Wasser, bitte.","expected":"ein wasser bitte","hint":"Ein Getränk bestellen"},{"prompt":"Was kostet das?","expected":"was kostet das","hint":"Nach dem Preis fragen"},{"prompt":"Danke, es war sehr lecker!","expected":"danke es war sehr lecker","hint":"Das Essen loben"},{"prompt":"Die Rechnung, bitte.","expected":"die rechnung bitte","hint":"Nach der Rechnung fragen"},{"prompt":"Ich hätte gerne einen Salat.","expected":"ich hätte gerne einen salat","hint":"Essen bestellen"},{"prompt":"Kann ich bitte die Tagesgerichte sehen?","expected":"kann ich bitte die tagesgerichte sehen","hint":"Nach den Tagesgerichten fragen"},{"prompt":"Ein Bier, bitte.","expected":"ein bier bitte","hint":"Ein Getränk bestellen"},{"prompt":"Ich bin Vegetarier.","expected":"ich bin vegetarier","hint":"Sich über Essensoptionen informieren"},{"prompt":"Könnte ich etwas mehr Brot bekommen?","expected":"könnte ich etwas mehr brot bekommen","hint":"Nach mehr Brot fragen"},{"prompt":"Hat das Gericht Nüsse?","expected":"hat das gericht nüsse","hint":"Nach Allergenen fragen"},{"prompt":"Ich möchte die Nachspeise.","expected":"ich möchte die nachspeise","hint":"Nach dem Dessert fragen"},{"prompt":"Ist das Essen scharf?","expected":"ist das essen scharf","hint":"Nach dem Schärfegrad fragen"},{"prompt":"Ein Glas Rotwein, bitte.","expected":"ein glas rotwein bitte","hint":"Ein Getränk bestellen"},{"prompt":"Kann ich die Speisekarte mitnehmen?","expected":"kann ich die speisekarte mitnehmen","hint":"Nach der Mitnahme der Karte fragen"},{"prompt":"Ich habe eine Reservierung.","expected":"ich habe eine reservierung","hint":"Sich zu einer Reservierung melden"},{"prompt":"Das Essen war köstlich!","expected":"das essen war köstlich","hint":"Ein Kompliment machen"},{"prompt":"Könnte ich die Zutatenliste sehen?","expected":"könnte ich die zutatenliste sehen","hint":"Nach den Zutaten fragen"},{"prompt":"Ich hätte gerne die Spezialität des Hauses.","expected":"ich hätte gerne die spezialität des hauses","hint":"Die Spezialität bestellen"}]}', 1),

('de', 'A2', 'reading', 'Eine kurze Geschichte', 'A Short Story', 'Eine einfache Geschichte verstehen', 'Understand a simple story',
'{"type":"read_and_choose","instructions":"Lies die Geschichte und antworte.","passage":"Tom steht um sieben Uhr auf. Er isst Toast und trinkt Orangensaft zum Frühstück. Dann geht er mit seinem Freund Sam zur Schule. In der Schule lernen sie Mathe und Bio.","exercises":[{"question":"Was isst Tom zum Frühstück?","options":["Toast","Müsli","Eier","Pfannkuchen"],"correct":0},{"question":"Mit wem geht Tom zur Schule?","options":["Lehrer","Mutter","Freund Sam","Allein"],"correct":2},{"question":"Wann steht Tom auf?","options":["6 Uhr","7 Uhr","8 Uhr","9 Uhr"],"correct":1},{"question":"Was lernt er?","options":["Sport","Mathe","Kunst","Musik"],"correct":1},{"question":"Was trinkt er?","options":["Wasser","Milch","Saft","Tee"],"correct":2},{"question":"Was macht Tom nach der Schule?","options":["Hausaufgaben","Fußball spielen","Ins Kino gehen","Lesen"],"correct":1},{"question":"Welches Fach mag Tom am meisten?","options":["Mathematik","Deutsch","Biologie","Geschichte"],"correct":0},{"question":"Wie lange dauert der Schulweg von Tom?","options":["5 Minuten","10 Minuten","15 Minuten","20 Minuten"],"correct":2},{"question":"Welches Getränk hat Tom zum Mittagessen?","options":["Wasser","Saft","Milch","Tee"],"correct":1},{"question":"Welches Hobby hat Tom?","options":["Zeichnen","Schwimmen","Gitarre spielen","Kochen"],"correct":2},{"question":"Was trägt Tom zur Schule?","options":["Hemd und Jeans","Sportkleidung","Schuluniform","Kurze Hosen"],"correct":0},{"question":"Wie oft geht Tom ins Schwimmbad?","options":["Einmal pro Woche","Zweimal pro Woche","Dreimal pro Woche","Nie"],"correct":1},{"question":"Was macht Tom am Wochenende?","options":["Fahrrad fahren","Freund besuchen","Fernsehen","Schlafen"],"correct":0},{"question":"Wo spielt Tom Fußball?","options":["Im Park","Auf dem Schulhof","In der Halle","Im Garten"],"correct":1},{"question":"Welche Farbe hat Toms Rucksack?","options":["Rot","Blau","Grün","Schwarz"],"correct":3},{"question":"Was liest Tom gerne?","options":["Romane","Comics","Nachrichten","Biografien"],"correct":1},{"question":"Wann macht Tom eine Pause?","options":["Nach der ersten Stunde","Nach der zweiten Stunde","Nach der dritten Stunde","Nach der vierten Stunde"],"correct":1},{"question":"Wie viele Freunde hat Tom?","options":["Einen","Drei","Fünf","Zehn"],"correct":2},{"question":"Was für ein Haustier hat Tom?","options":["Katze","Hund","Vogel","Keins"],"correct":1},{"question":"Wie oft spielt Tom Videospiele?","options":["Jeden Tag","Einmal pro Woche","Selten","Nie"],"correct":0}]}', 1),

('de', 'A2', 'writing', 'Sätze vervollständigen', 'Completing Sentences', 'Wörter in Lücken tippen', 'Type words into gaps',
'{"type":"fill_blank_type","instructions":"Tippe das fehlende Wort.","exercises":[{"sentence":"Ich ___ jeden Tag zur Schule.","expected":"gehe","hint":"Verb für laufen","hint_translation":"Verb for walking/going"},{"sentence":"Sie ___ gestern ein rotes Kleid.","expected":"trug","hint":"Vergangenheit von tragen","hint_translation":"Past tense of wearing"},{"sentence":"Wir ___ um sieben zu Abend.","expected":"essen","hint":"Was man mit Essen macht","hint_translation":"What you do with food"},{"sentence":"Er ___ seine Hausaufgaben.","expected":"macht","hint":"Eine Tätigkeit ausführen","hint_translation":"Perform an activity"},{"sentence":"Sie ___ im Park.","expected":"spielen","hint":"Spaß haben","hint_translation":"Have fun"},{"sentence":"Er ___ jeden Morgen joggen.","expected":"geht","hint":"Verb für Sport machen","hint_translation":"Verb for doing sports"},{"sentence":"Wir ___ am Wochenende einen Ausflug.","expected":"machen","hint":"Aktivität für einen speziellen Anlass","hint_translation":"Activity for a special occasion"},{"sentence":"Sie ___ das Buch sehr spannend.","expected":"findet","hint":"Meinung über etwas","hint_translation":"Opinion about something"},{"sentence":"Ich ___ gerne Musik.","expected":"höre","hint":"Was man mit Lautsprechern macht","hint_translation":"What you do with speakers"},{"sentence":"Er ___ seine Freunde zum Geburtstag ein.","expected":"lädt","hint":"Einladen zu einer Feier","hint_translation":"Inviting to a celebration"},{"sentence":"Wir ___ oft ins Kino.","expected":"gehen","hint":"Aktivität für Unterhaltung","hint_translation":"Activity for entertainment"},{"sentence":"Du ___ die Fragen sehr gut.","expected":"beantwortest","hint":"Antworten auf etwas geben","hint_translation":"Giving answers to something"},{"sentence":"Sie ___ jeden Abend einen Spaziergang.","expected":"macht","hint":"Bewegung in der Natur","hint_translation":"Movement in nature"},{"sentence":"Ich ___ gerne neue Rezepte.","expected":"probiere","hint":"Etwas Neues testen","hint_translation":"Testing something new"},{"sentence":"Er ___ seine Hausaufgaben immer pünktlich.","expected":"macht","hint":"Schulaufgaben erledigen","hint_translation":"Completing school tasks"},{"sentence":"Wir ___ die Stadt besichtigen.","expected":"werden","hint":"Zukunftsform für Aktivitäten","hint_translation":"Future form for activities"},{"sentence":"Sie ___ oft im Park.","expected":"spielen","hint":"Aktivität für Spaß","hint_translation":"Activity for fun"},{"sentence":"Ich ___ meine Freunde am Wochenende.","expected":"treffe","hint":"Zusammenkommen mit Menschen","hint_translation":"Meeting with people"},{"sentence":"Er ___ jeden Tag ein bisschen.","expected":"lernt","hint":"Wissen erwerben","hint_translation":"Acquiring knowledge"},{"sentence":"Wir ___ eine schöne Zeit zusammen.","expected":"haben","hint":"Erleben von Freude","hint_translation":"Experiencing joy"}]}', 1);
